class Trie01Vector {
private:
	struct TrieNode {
		array<int, 2> children; // 指向孩子的 id
		TrieNode() : children{ 0, 0 } {}
	};

	vector<TrieNode> tr;
	int newNode() { tr.push_back(TrieNode()); return ++nodeCnt; }

	int MAX;
	int root = 1;
	int nodeCnt = 1;
	map<ll, vector<int>> mp;
public:
	Trie01Vector(int MAX) :MAX(MAX), tr(2) {}

	void insert(int num, int id) {
		mp[num].pb(id);
		int now = root;
		for (int i = MAX; i >= 0; i--) {
			bool bit = (num >> i) & 1; // 当前数位
			if (not tr[now].children[bit]) {
				int tmp = newNode();
				tr[now].children[bit] = tmp;
			}
			now = tr[now].children[bit];
		}
	}

	vector<int>
		dfs(vector<pll>& dp, int now, int i, ll pre)
	{ // 归并排序求逆序对
		if (tr[now].children[0] and tr[now].children[1]) {
			var to = array<int, 2>{ 
				tr[now].children[0],
				tr[now].children[1]
			};
			var res = array<vector<int>, 2>{ 
				dfs(dp, to[0], i - 1, pre), 
				dfs(dp, to[1], i - 1, pre + (1ll << i)) 
			};

			// 算跨越两区间的逆序对/正序对个数
			// 未反转 i 位时，前[0] 后[1]
			int j = 0;
			for (int x : res[1]) {
				while (j <= vs(res[0]) and res[0][j] <= x)j++;
				dp[i].px += vs(res[0]) - j + 1;
				dp[i].py += j;
			}

			// 插入排序
			var fres = vector<int>();
			int k = 0; j = 0;
			while (k <= vs(res[0]) and j <= vs(res[1])) {
				if (res[0][k] < res[1][j]) {
					fres.pb(res[0][k]);
					k++;
				}
				else {
					fres.pb(res[1][j]);
					j++;
				}
			}
			while (k <= vs(res[0])) {
				fres.pb(res[0][k]);
				k++;
			}
			while (j <= vs(res[1])) {
				fres.pb(res[1][j]);
				j++;
			}
			return fres;
		}
		else if (tr[now].children[0]) {
			return dfs(dp, tr[now].children[0], i - 1, pre);
 		}
		else if (tr[now].children[1]) {
			return dfs(dp, tr[now].children[1], i - 1, pre + (1ll << i));
		}
		else {
			return mp[pre];
		}
	}

	pll get() {
		// 第 i 位不翻转的情况下，跨越两区间的逆序对/正序对个数
		var dp = vector<pll>(31); 
		dfs(dp, root, MAX, 0);
		pll res = { 0,0 };
		fb(i, MAX, 0) {
			// i 位翻转，两区间位置翻转，正序对变成逆序对
			if (dp[i].px <= dp[i].py)res.px += dp[i].px;
			else {
				res.px += dp[i].py;
				res.py += (1ll << i);
			}
		}
		return res;
	}
};

